import React, { useState } from 'react';

export default function AdminUsers({ searchQuery, filters, onRefresh }) {
  const [users, setUsers] = useState([
    { id: 1, email: 'jean.dupont@mail.com', name: 'Jean Dupont', role: 'courtier', status: 'active', verified: true, mfa: true, lastLogin: new Date(Date.now() - 2 * 60 * 60 * 1000) },
    { id: 2, email: 'marie.martin@mail.com', name: 'Marie Martin', role: 'assureur', status: 'active', verified: true, mfa: false, lastLogin: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000) },
    { id: 3, email: 'pierre.bernard@mail.com', name: 'Pierre Bernard', role: 'client', status: 'active', verified: true, mfa: true, lastLogin: new Date(Date.now() - 3 * 60 * 60 * 1000) },
    { id: 4, email: 'sophie.rousseau@mail.com', name: 'Sophie Rousseau', role: 'client', status: 'inactive', verified: true, mfa: false, lastLogin: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000) },
    { id: 5, email: 'olivier.lefevre@mail.com', name: 'Olivier Lefèvre', role: 'courtier', status: 'suspended', verified: false, mfa: false, lastLogin: new Date(Date.now() - 60 * 24 * 60 * 60 * 1000) },
    { id: 6, email: 'admin@cyber.fr', name: 'Admin System', role: 'admin', status: 'active', verified: true, mfa: true, lastLogin: new Date(Date.now() - 30 * 60 * 1000) },
  ]);

  const [showModal, setShowModal] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [formData, setFormData] = useState({
    email: '',
    name: '',
    role: 'client',
  });

  const filteredUsers = users.filter(user => {
    const matchSearch = searchQuery === '' || 
      user.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
      user.name.toLowerCase().includes(searchQuery.toLowerCase());
    
    const matchRole = !filters.role || user.role === filters.role;
    const matchStatus = !filters.status || user.status === filters.status;
    
    return matchSearch && matchRole && matchStatus;
  });

  const getRoleLabel = (role) => {
    const labels = {
      admin: 'Administrateur',
      assureur: 'Assureur',
      courtier: 'Courtier',
      client: 'Client',
    };
    return labels[role] || role;
  };

  const formatDate = (date) => {
    return date.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
  };

  const handleAddUser = () => {
    setSelectedUser(null);
    setFormData({ email: '', name: '', role: 'client' });
    setShowModal(true);
  };

  const handleEditUser = (user) => {
    setSelectedUser(user);
    setFormData({ email: user.email, name: user.name, role: user.role });
    setShowModal(true);
  };

  const handleSaveUser = () => {
    if (selectedUser) {
      setUsers(users.map(u => u.id === selectedUser.id ? { ...u, ...formData } : u));
    } else {
      setUsers([...users, { id: users.length + 1, ...formData, status: 'active', verified: false, mfa: false, lastLogin: new Date() }]);
    }
    setShowModal(false);
    onRefresh();
  };

  const handleDeleteUser = (id) => {
    if (window.confirm('Êtes-vous sûr de vouloir supprimer cet utilisateur ?')) {
      setUsers(users.filter(u => u.id !== id));
      onRefresh();
    }
  };

  const handleToggleMFA = (id) => {
    setUsers(users.map(u => u.id === id ? { ...u, mfa: !u.mfa } : u));
  };

  return (
    <div className="admin-users">
      <div className="admin-section">
        <div className="admin-section-header">
          <h2 className="admin-section-title">Gestion des utilisateurs</h2>
          <div className="admin-section-actions">
            <button className="admin-btn admin-btn--primary" onClick={handleAddUser}>
              ➕ Ajouter utilisateur
            </button>
          </div>
        </div>

        {filteredUsers.length > 0 ? (
          <div style={{ overflowX: 'auto' }}>
            <table className="admin-table">
              <thead>
                <tr>
                  <th>Utilisateur</th>
                  <th>Email</th>
                  <th>Rôle</th>
                  <th>Statut</th>
                  <th>Vérification</th>
                  <th>MFA</th>
                  <th>Dernière connexion</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredUsers.map(user => (
                  <tr key={user.id}>
                    <td>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <div style={{
                          width: '32px',
                          height: '32px',
                          borderRadius: '6px',
                          background: 'rgba(77,255,180,0.1)',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: '12px',
                          fontWeight: 600,
                          color: '#4DFFB4',
                        }}>
                          {user.name[0].toUpperCase()}
                        </div>
                        <span>{user.name}</span>
                      </div>
                    </td>
                    <td style={{ fontFamily: 'var(--f-mono)', fontSize: '11px' }}>{user.email}</td>
                    <td>
                      <span className={`admin-badge admin-badge--${user.role}`}>
                        {getRoleLabel(user.role)}
                      </span>
                    </td>
                    <td>
                      <span className={`admin-badge admin-badge--${user.status}`}>
                        {user.status === 'active' ? 'Actif' : user.status === 'inactive' ? 'Inactif' : 'Suspendu'}
                      </span>
                    </td>
                    <td>
                      <span className={`admin-badge ${user.verified ? 'admin-badge--verified' : 'admin-badge--unverified'}`}>
                        {user.verified ? '✓ Vérifié' : 'Non vérifié'}
                      </span>
                    </td>
                    <td>
                      <button
                        onClick={() => handleToggleMFA(user.id)}
                        className="admin-btn admin-btn--small"
                        style={{
                          background: user.mfa ? 'rgba(77,255,180,0.1)' : 'rgba(255,68,102,0.1)',
                          borderColor: user.mfa ? 'rgba(77,255,180,0.2)' : 'rgba(255,68,102,0.2)',
                          color: user.mfa ? '#4DFFB4' : '#FF4466',
                        }}
                      >
                        {user.mfa ? '🔐 Activé' : '⚠️ Inactif'}
                      </button>
                    </td>
                    <td>{formatDate(user.lastLogin)}</td>
                    <td>
                      <div style={{ display: 'flex', gap: '6px' }}>
                        <button
                          className="admin-btn admin-btn--small"
                          onClick={() => handleEditUser(user)}
                          style={{ background: 'rgba(0,212,255,0.1)', color: '#00D4FF', borderColor: 'rgba(0,212,255,0.2)' }}
                        >
                          ✏️ Modifier
                        </button>
                        <button
                          className="admin-btn admin-btn--small admin-btn--danger"
                          onClick={() => handleDeleteUser(user.id)}
                        >
                          🗑️ Supprimer
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="admin-empty">
            <div className="admin-empty-icon">👤</div>
            <div className="admin-empty-title">Aucun utilisateur trouvé</div>
            <div className="admin-empty-description">
              {searchQuery || Object.keys(filters).length > 0
                ? 'Modifiez vos critères de recherche et de filtrage.'
                : 'Créez votre premier utilisateur pour commencer.'}
            </div>
            <button className="admin-btn admin-btn--primary" onClick={handleAddUser}>
              ➕ Créer utilisateur
            </button>
          </div>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div className="admin-modal" onClick={() => setShowModal(false)}>
          <div className="admin-modal-content" onClick={e => e.stopPropagation()}>
            <h2 className="admin-modal-header">
              {selectedUser ? 'Modifier utilisateur' : 'Ajouter utilisateur'}
            </h2>

            <form className="admin-form">
              <div className="admin-form-group">
                <label className="admin-form-label">Nom complet</label>
                <input
                  type="text"
                  className="admin-form-input"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="Ex: Jean Dupont"
                />
              </div>

              <div className="admin-form-group">
                <label className="admin-form-label">Email</label>
                <input
                  type="email"
                  className="admin-form-input"
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                  placeholder="jean@example.com"
                  disabled={!!selectedUser}
                />
              </div>

              <div className="admin-form-group">
                <label className="admin-form-label">Rôle</label>
                <select
                  className="admin-form-select"
                  value={formData.role}
                  onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                >
                  <option value="client">Client</option>
                  <option value="courtier">Courtier</option>
                  <option value="assureur">Assureur</option>
                  <option value="admin">Administrateur</option>
                </select>
              </div>

              <div className="admin-form-actions">
                <button
                  type="button"
                  className="admin-btn"
                  onClick={() => setShowModal(false)}
                >
                  Annuler
                </button>
                <button
                  type="button"
                  className="admin-btn admin-btn--primary"
                  onClick={handleSaveUser}
                >
                  {selectedUser ? 'Mettre à jour' : 'Créer'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
